import React from 'react';
import { motion } from 'framer-motion';

function Blog() {
  const articles = [
    {
      id: 1,
      titre: 'Sécurité dans Active Directory Certificate Services',
      date: '07 Mars 2026',
      categorie: 'Cybersécurité',
      description: 'Dans cet article, je partage mon travail de fin d\'études sur la sécurité des certificats numériques dans Windows Server. J\'y aborde les vulnérabilités d\'AD CS et les stratégies de remédiation.',
      temps: '10 min',
      icon: '🔒'
    },
    {
      id: 2,
      titre: 'Introduction à Kali Linux pour débutants',
      date: 'Bientôt disponible',
      categorie: 'Linux',
      description: 'Un guide complet pour installer et configurer Kali Linux, les outils essentiels et les premières étapes en cybersécurité.',
      temps: '8 min',
      icon: '🐧'
    },
    {
      id: 3,
      titre: 'Comment configurer un VPN sur Linux',
      date: 'Bientôt disponible',
      categorie: 'Réseaux',
      description: 'Tutoriel pas à pas pour mettre en place un VPN sécurisé avec OpenVPN sur Linux.',
      temps: '6 min',
      icon: '🌐'
    },
    {
      id: 4,
      titre: 'Les bases de la cybersécurité en entreprise',
      date: 'Bientôt disponible',
      categorie: 'Cybersécurité',
      description: 'Les bonnes pratiques de sécurité informatique pour protéger votre entreprise contre les cyberattaques.',
      temps: '7 min',
      icon: '🛡️'
    }
  ];

  const categories = ['Tous', 'Cybersécurité', 'Réseaux', 'Linux', 'Windows'];
  const [categActive, setCategActive] = React.useState('Tous');

  const articlesFiltres = categActive === 'Tous'
    ? articles
    : articles.filter(a => a.categorie === categActive);

  return (
    <div style={{background: '#000000', minHeight: '100vh', paddingTop: '100px'}}>

      {/* HEADER */}
      <motion.section
        initial={{opacity: 0, y: -30}}
        animate={{opacity: 1, y: 0}}
        transition={{duration: 0.8}}
        style={{
          textAlign: 'center', padding: '60px 20px',
          background: 'radial-gradient(ellipse at center, #0a1a0a 0%, #000000 70%)',
          borderBottom: '2px solid #00aa00'
        }}
      >
        <h1 style={{fontSize: '48px', color: '#ffd700', letterSpacing: '4px', marginBottom: '15px'}}>
          Blog
        </h1>
        <p style={{color: '#aaaaaa', fontSize: '18px', maxWidth: '600px', margin: '0 auto'}}>
          Bienvenue sur mon blog — je partage mes expériences, apprentissages et projets dans le monde des réseaux, systèmes et cybersécurité.
        </p>
      </motion.section>

      {/* FILTRES */}
      <section style={{padding: '40px 50px', textAlign: 'center'}}>
        <div style={{display: 'flex', justifyContent: 'center', gap: '15px', flexWrap: 'wrap'}}>
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setCategActive(cat)}
              style={{
                background: categActive === cat ? '#00aa00' : 'transparent',
                color: categActive === cat ? '#ffffff' : '#aaaaaa',
                border: '1px solid #00aa00',
                padding: '8px 20px', borderRadius: '20px',
                cursor: 'pointer', fontSize: '14px',
                transition: 'all 0.3s'
              }}
            >
              {cat}
            </button>
          ))}
        </div>
      </section>

      {/* ARTICLES */}
      <section style={{padding: '20px 50px 80px', maxWidth: '1200px', margin: '0 auto'}}>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
          gap: '30px'
        }}>
          {articlesFiltres.map((article, index) => (
            <motion.div
              key={article.id}
              initial={{opacity: 0, y: 30}}
              whileInView={{opacity: 1, y: 0}}
              whileHover={{scale: 1.03, boxShadow: '0 0 25px rgba(0,170,0,0.3)'}}
              transition={{duration: 0.4, delay: index * 0.1}}
              style={{
                background: '#0a0a0a', border: '1px solid #00aa00',
                borderRadius: '15px', padding: '30px',
                cursor: 'pointer'
              }}
            >
              <div style={{fontSize: '40px', marginBottom: '15px'}}>{article.icon}</div>
              <div style={{display: 'flex', gap: '10px', marginBottom: '12px', flexWrap: 'wrap'}}>
                <span style={{
                  background: '#00aa00', color: '#ffffff',
                  padding: '3px 12px', borderRadius: '12px', fontSize: '12px'
                }}>
                  {article.categorie}
                </span>
                <span style={{color: '#555555', fontSize: '12px', paddingTop: '3px'}}>
                  ⏱ {article.temps} de lecture
                </span>
              </div>
              <h3 style={{color: '#ffd700', fontSize: '18px', marginBottom: '12px', lineHeight: '1.4'}}>
                {article.titre}
              </h3>
              <p style={{color: '#aaaaaa', fontSize: '14px', lineHeight: '1.7', marginBottom: '20px'}}>
                {article.description}
              </p>
              <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                <span style={{color: '#555555', fontSize: '12px'}}>{article.date}</span>
                <button style={{
                  background: 'transparent', color: '#00aa00',
                  border: '1px solid #00aa00', padding: '6px 18px',
                  borderRadius: '15px', cursor: 'pointer', fontSize: '13px'
                }}>
                  Lire →
                </button>
              </div>
            </motion.div>
          ))}
        </div>
      </section>
    </div>
  );
}

export default Blog;
